INSERT INTO `caipiao_news` VALUES 
(3,30,'Giới thiệu trang web','Về chúng tôi 111','<p>\r\n "Xổ số là chứng nhận do nhà nước cấp phép phát hành, bán hợp pháp để huy động quỹ công ích xã hội, thúc đẩy sự phát triển của các hoạt động công ích xã hội. Cá nhân tự nguyện mua và có cơ hội trúng thưởng theo các quy tắc cụ thể."<br />\r\nHiện tại, các loại xổ số được cấp phép phát hành bao gồm Xổ số Phúc lợi Trung Quốc và Xổ số Thể thao Trung Quốc, lần lượt do Bộ Dân chính và Tổng cục Thể thao phát hành và phân phối.<br />\r\nLấy sản phẩm xổ số chủ đạo của Xổ số Phúc lợi Trung Quốc làm ví dụ, tỷ lệ cơ cấu doanh thu bán vé số như sau: 75% hoàn trả tiền thưởng, 1% quỹ điều tiết bán hàng, 5% chi phí phát hành, 19% quỹ công ích.<br />\r\nTrong đó, quỹ công ích của xổ số phúc lợi chủ yếu được đầu tư vào các hoạt động phúc lợi và từ thiện; đối với xổ số thể thao, chủ yếu được đầu tư vào cơ sở vật chất thể thao quần chúng, các dự án Olympic, v.v.<br />\r\nMục đích mua xổ số\r\n</p>\r\n<p>\r\n Mua xổ số là một hành động thiện nguyện ủng hộ sự nghiệp công ích của Trung Quốc. Bỏ ra 2 tệ mua một vé số không nhiều, nhưng tình yêu thương được truyền đạt là vô hạn.<br />\r\nMục đích mua xổ số của khách hàng nên dựa trên nền tảng lòng nhân ái, giải trí và trong khả năng tài chính cho phép. Không nên vì tâm lý ăn may để trúng giải lớn mà liều lĩnh sử dụng những nguồn vốn không nên dùng.<br />\r\nĐội ngũ Xổ số\r\n</p>\r\n<p>\r\n Nền tảng xổ số hiện có hơn 250 nhân viên, là một đội ngũ trẻ trung tràn đầy sức sống và đang trong thời kỳ mở rộng nhanh chóng.<br />\r\nTriết lý quản lý của chúng tôi là cung cấp cho mọi người một môi trường làm việc thoải mái và thư giãn nhất có thể, hoàn toàn tôn trọng giá trị của mỗi cá nhân. Mặc dù vẫn còn nhiều thiếu sót trong quản lý, nhưng chúng tôi luôn cố gắng để trở nên minh bạch, lành mạnh và chuẩn mực.<br />\r\nMạng lưới xổ số luôn mở rộng cánh cửa đón nhận nhân tài, cung cấp cho những người có chí hướng không gian phát triển rộng lớn, với mức lương và chế độ đãi ngộ hậu hĩnh.<br />\r\nTuân thủ triết lý cùng chia sẻ, với mục đích xây dựng một đội ngũ khởi nghiệp đầy nhiệt huyết, chúng tôi đã chuẩn bị một lượng lớn cổ tức và phần thưởng quyền chọn cho tất cả các nhân viên có đóng góp cho công ty.\r\n</p>',1480805970),
(10,34,'Vấn đề bảo mật','Tham gia trò chơi có an toàn không?','<p>\r\n  <span style=\"font-size:16px;\">Mạng K3 cam kết: </span>\r\n</p>\r\n<p>\r\n  <span style=\"font-size:16px;\">1. Mạng K3 sử dụng công nghệ mã hóa SSL 128-bit và hệ thống quản lý bảo mật nghiêm ngặt để đảm bảo sự an toàn của khách hàng được bảo vệ hoàn hảo nhất. </span>\r\n</p>\r\n<p>\r\n <span style=\"font-size:16px;\"> 2. Tất cả các khoản cá cược của khách hàng đều được thực hiện trong điều kiện bảo mật cực kỳ nghiêm ngặt, chúng tôi tuyệt đối sẽ không tiết lộ thông tin khách hàng cho bất kỳ bên thứ ba nào. </span>\r\n</p>\r\n<p>\r\n <span style=\"font-size:16px;\"> 3. Chúng tôi áp dụng các biện pháp bảo mật và phòng chống lừa đảo nghiêm ngặt đối với mọi giao dịch, đảm bảo tính hợp pháp và chân thực của tài khoản người chơi, đồng thời đảm bảo an toàn cho các giao dịch và thanh toán của người chơi.</span>\r\n</p>\r\n<p>\r\n  <span style=\"font-size:16px;\"> 4. Tính bảo mật của mạng K3 đứng đầu trong ngành, xin quý khách yên tâm trải nghiệm.</span>\r\n</p>',1480812017),
(11,41,'Hoạt động khuyến mãi','Chương trình tặng thưởng nạp tiền một lần','Chương trình tặng thưởng nạp tiền một lần<strong></strong> Vui lòng liên hệ bộ phận chăm sóc khách hàng để biết số tiền hoàn trả khuyến mãi cụ thể.<br />',1480815430),
(14,34,'Vấn đề bảo mật','Giới thiệu Quan Min Xing Cai','Quan Min Xing Cai (Toàn Dân Tinh Thái) là nền tảng xổ số chuyên biệt quy mô lớn duy nhất trên toàn quốc do Trung tâm Xổ số Phúc lợi Trung Quốc ra mắt. Nền tảng này bao gồm tất cả các cách chơi xổ số trong nước, cam kết thúc đẩy sự phát triển của trò chơi K3 tại Trung Quốc. Quan Min Xing Cai hiện là trò chơi mở thưởng nhanh phổ biến nhất trong nước, đã phủ sóng thành công tại 13 tỉnh thành, với gần chục triệu người chơi tham gia mua vé số K3, đạt doanh thu hàng chục tỷ nhân dân tệ.\r\n<p class=\"p2\">\r\n  Quan Min Xing Cai ra đời nhằm giúp người chơi có thể lấy dữ liệu quay thưởng xổ số của các tỉnh, phân tích dự đoán một cách đơn giản và nhanh chóng hơn. Cung cấp xu hướng chuyên nghiệp, dữ liệu nhịp gan (số chưa về), để người chơi có thể chơi chuyên nghiệp hơn và trúng nhiều tiền thưởng hơn. Không chỉ vậy, Quan Min Xing Cai còn liên kết với một số tỉnh thành mở dịch vụ đặt cược xổ số trực tuyến. Điều này mang lại sự thuận tiện tuyệt vời cho người dùng, hiện thực hóa việc có thể mua xổ số K3 mọi lúc, mọi nơi. Đồng thời, Quan Min Xing Cai cũng đã ra mắt ứng dụng điện thoại, tích hợp với WeChat và Alipay để người chơi có thể tận hưởng sự tiện lợi của internet di động.\r\n</p>\r\n<p class=\"p3\">\r\n  Quan Min Xing Cai hy vọng sẽ đồng hành cùng sự phát triển của ngành xổ số phúc lợi Trung Quốc, kiên trì đặt lợi ích của người chơi xổ số lên hàng đầu, cam kết cung cấp dữ liệu xổ số an toàn, ổn định và đáng tin cậy, phấn đấu trở thành nền tảng dịch vụ xổ số hàng đầu Trung Quốc!\r\n</p>',1480965304),
(15,34,'Vấn đề bảo mật','Thông tin sau khi đăng ký có bị rò rỉ không?','<strong>Khi bạn đăng ký trở thành thành viên của chúng tôi, khách hàng có thể cần điền một số thông tin cá nhân, chẳng hạn như tên, địa chỉ, Email, số điện thoại và tài khoản ngân hàng, để chúng tôi cung cấp cho bạn các dịch vụ toàn diện, kịp thời và thuận tiện hơn. Tại đây, chúng tôi trịnh trọng cam kết với bạn rằng chúng tôi sẽ bảo vệ quyền riêng tư của thành viên và nền tảng này sẽ không tiết lộ thông tin khách hàng trong bất kỳ trường hợp nào!</strong>',1480965354),
(16,34,'Vấn đề bảo mật','Cài đặt và giới thiệu Trung tâm bảo mật','<p>\r\n Nền tảng của chúng tôi áp dụng hệ thống xác thực kép độc quyền bằng Số điện thoại và Email, tạo ra một kênh xác minh hoàn toàn mới.\r\n</p>\r\n<p>\r\n Mang đến trải nghiệm an toàn nhất cho người dùng.\r\n        Chúng tôi khuyên bạn nên hoàn thiện các thông tin bảo mật sau để nâng cao mức độ an toàn cho tài khoản và bảo vệ tiền của bạn tốt hơn.\r\n</p>\r\n<p>\r\n Câu hỏi 1: Mã xác minh thời gian thực của Số điện thoại và Email là gì?\r\n</p>\r\n<p>\r\n  Khi đăng nhập lần đầu, bạn cần làm theo hướng dẫn để liên kết Email và Số điện thoại. Sau khi liên kết, mọi thao tác sau này đều phải được bảo vệ bằng xác minh qua mã xác minh.\r\n</p>\r\n<p>\r\n Câu hỏi 2: Câu hỏi bảo mật là gì?\r\n</p>\r\n<p>\r\n  Câu hỏi bảo mật được sử dụng để khôi phục thông tin tài khoản nền tảng của bạn. Sau khi liên kết, bạn có thể lấy lại tài khoản thông qua câu hỏi bảo mật.\r\n</p>\r\n<p>\r\n Câu hỏi 3: Tác dụng của việc liên kết Email?\r\n</p>\r\n<p>\r\n Liên kết Email có thể tăng mức độ bảo mật tài khoản và cũng đảm bảo bạn có thể lấy lại mã xác minh thời gian thực trong trường hợp Email hoạt động bình thường.\r\n</p>',1480965410),
(17,35,'Vấn đề nạp tiền','Lưu ý khi chuyển khoản ngân hàng trực tuyến','<ul class=\"ul_help\" id=\"ul_help_s\">\r\n <li style=\"background-color:#fff;\">\r\n   <div class=\"hc_cont\">\r\n     <strong><span style=\"color:#333333;font-family:\'Microsoft Yahei\', \'Hiragino Sans GB\', \'Helvetica Neue\', Helvetica, tahoma, arial, Verdana, sans-serif, \'WenQuanYi Micro Hei\', 宋体;font-size:14px;line-height:24px;background-color:#FFFFFF;\">Hiện tại chuyển khoản ngân hàng trực tuyến chỉ hỗ trợ: Ngân hàng Công thương (ICBC) và Ngân hàng Xây dựng (CCB). Các thành viên không có thẻ của 2 ngân hàng này cần sử dụng các ngân hàng khác để chuyển khoản liên ngân hàng;</span> \r\n      <p style=\"color:#666666;font-family:\'Microsoft Yahei\', \'Hiragino Sans GB\', \'Helvetica Neue\', Helvetica, tahoma, arial, Verdana, sans-serif, \'WenQuanYi Micro Hei\', 宋体;font-size:14px;background-color:#FFFFFF;\">\r\n        Để tiền nạp của bạn được cập nhật kịp thời, khi sử dụng tính năng chuyển khoản liên ngân hàng, vui lòng cố gắng sử dụng tính năng <strong>\"Chuyển khoản chuyển phát nhanh\" (加急汇款)</strong> \r\n      </p>\r\n      <p style=\"color:#666666;font-family:\'Microsoft Yahei\', \'Hiragino Sans GB\', \'Helvetica Neue\', Helvetica, tahoma, arial, Verdana, sans-serif, \'WenQuanYi Micro Hei\', 宋体;font-size:14px;background-color:#FFFFFF;\">\r\n        Thời gian sử dụng tính năng \"Chuyển khoản chuyển phát nhanh\" là từ thứ Hai đến thứ Sáu, 09:00 - 16:30. Các thời gian khác và ngày lễ không có tùy chọn chuyển phát nhanh. Chúng tôi khuyên bạn nên nạp tiền trong khung giờ hỗ trợ chuyển phát nhanh để tiền vào tài khoản nhanh chóng.\r\n      </p>\r\n</strong>\r\n   </div>\r\n  </li>\r\n</ul>',1480965470),
(18,35,'Vấn đề nạp tiền','Quy trình nạp tiền qua Ngân hàng Công Thương (ICBC)','<p>\r\n <strong>Bước 1: Nhấp vào nút \"Trung tâm thành viên - Quản lý quỹ - Tôi muốn nạp tiền - Chuyển khoản ngân hàng trực tuyến\" trên trang chủ, chọn \"Ngân hàng Công Thương (ICBC)\", nhập số tiền, sau đó nhấp \"Tiếp theo\"</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang1.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 2: Lấy thông tin nạp tiền và vui lòng chắc chắn sử dụng tính năng \"Sao chép\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang2.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 3: Nhấp vào \"Đăng nhập Internet Banking để thanh toán\", vào mục ngân hàng ICBC và nhấp vào thanh Menu phía trên \"Chuyển khoản\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang3.jpg\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 4: Nhấp vào \"Chuyển khoản trong nước\" ở phía bên trái trang</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang4.jpg\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 5: Sử dụng tính năng \"Sao chép\", dán các thông tin bắt buộc như \"Tên người nhận, Số tài khoản người nhận hoặc E-mail người nhận, Nội dung đính kèm\" vào các mục tương ứng trên Internet Banking (Lưu ý: Vui lòng sao chép \"Nội dung đính kèm\" của đơn nạp tiền và dán vào mục \"Nội dung gửi người nhận\" trên trang Internet Banking)</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang5.jpg\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 6: Nhấp \"Gửi\", hệ thống sẽ thông báo giao dịch thành công</strong> \r\n</p>',1480965488),
(19,35,'Vấn đề nạp tiền','Quy trình nạp tiền qua Ngân hàng Xây dựng (CCB)','<p>\r\n <strong>Bước 1: Nhấp vào nút \"Trung tâm thành viên - Quản lý quỹ - Tôi muốn nạp tiền - Chuyển khoản ngân hàng trực tuyến\" trên trang chủ, chọn \"Ngân hàng Xây dựng\", nhập số tiền, sau đó nhấp \"Tiếp theo\"</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/jianhang1.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 2: Lấy thông tin nạp tiền</strong> \r\n</p>\r\n<p>\r\n <strong><img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/jianhang2.png\" /></strong> \r\n</p>\r\n<p>\r\n <strong>Bước 3: Nhấp vào \"Chuyển khoản\", sau đó nhấp vào \"Chuyển khoản vãng lai\", chuyển sang trang chuyển khoản liên ngân hàng</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/jianhang3.jpg\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 4: Sử dụng tính năng sao chép, dán các thông tin bắt buộc như \"Tên tài khoản người nhận, Số tài khoản người nhận, Lời nhắn đính kèm\" vào các ô tương ứng trên Internet Banking. (Lưu ý: Sao chép chính xác lời nhắn đính kèm và dán vào mục Lời nhắn đính kèm)</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/jianhang4.jpg\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 5: Chuyển sang trang xác nhận thông tin chuyển khoản và nhấp vào \"Xác nhận\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/jianhang5.jpg\" /> \r\n</p>\r\n<p>\r\n  <b>Bước 6: Nhập \"Mật khẩu U-Key\" của CCB để thanh toán</b> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/jianhang6.jpg\" /> \r\n</p>\r\n<p>\r\n  <b>Bước 7: Sau khi xác nhận thông tin thanh toán, trang sẽ chuyển sang \"Giao dịch chuyển khoản thành công\" </b> \r\n</p>',1480965506),
(20,35,'Vấn đề nạp tiền','Quy trình chuyển tiền từ Ngân hàng Nông nghiệp (ABC) sang Công Thương','<p>\r\n <strong>Bước 1: Nhấp vào nút \"Trung tâm thành viên - Quản lý quỹ - Tôi muốn nạp tiền - Chuyển khoản ngân hàng trực tuyến\" trên trang chủ, chọn \"Ngân hàng Công Thương (ICBC)\", nhập số tiền, sau đó nhấp \"Tiếp theo\"</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang1.png\" /> \r\n</p>\r\n<p>\r\n <b>Bước 2: Lấy thông tin nạp tiền</b> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang2.png\" /> \r\n</p>\r\n<p>\r\n <b>Bước 3: Nhấp vào \"Đăng nhập chuyển khoản Internet Banking\", sau đó nhấp \"Chuyển khoản một lần\"</b> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/nonghang3.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 4: Thêm \"Người nhận mới\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/nonghang4.png\" /> \r\n</p>\r\n<p>\r\n  <b>Bước 5: Sử dụng tính năng sao chép, dán các thông tin như \"Số tài khoản, Tên tài khoản, Chi nhánh mở thẻ\" vào các ô tương ứng trên Internet Banking</b> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/nonghang5.png\" /> \r\n</p>\r\n<p>\r\n  <b>Bước 6: Sao chép thông tin \"Nội dung đính kèm\" từ nền tảng và dán vào mục \"Mục đích chuyển tiền\"</b> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/nonghang6.png\" /> \r\n</p>\r\n<p>\r\n  <b>Bước 7: Nhập \"Mật khẩu thanh toán\" và nhấp \"Gửi\". Bước 8: Sau khi xác nhận thông tin thanh toán, trang sẽ chuyển sang \"Giao dịch chuyển khoản thành công\"</b> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/nonghang7.png\" /> \r\n</p>\r\n<b>Bước 8: Sau khi xác nhận thông tin thanh toán, trang sẽ chuyển sang \"Giao dịch chuyển khoản thành công\"</b>',1480965525),
(21,35,'Vấn đề nạp tiền','Quy trình chuyển tiền từ Ngân hàng Minsheng sang Công Thương','<p>\r\n <strong>Bước 1: Nhấp vào nút \"Trung tâm thành viên - Quản lý quỹ - Tôi muốn nạp tiền - Chuyển khoản ngân hàng trực tuyến\" trên trang chủ, chọn \"Ngân hàng Công Thương (ICBC)\", nhập số tiền, sau đó nhấp \"Tiếp theo\"</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang1.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 2: Lấy thông tin nạp tiền</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang2.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 3: Đăng nhập vào trang Internet Banking, nhấp vào \"Chuyển khoản\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/minsheng3.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 4: Chọn \"Chuyển khoản liên ngân hàng\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/minsheng4.jpg\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 5: Sử dụng tính năng sao chép, dán các thông tin như \"Tên tài khoản người nhận, Số tài khoản người nhận, Nội dung đính kèm\" vào các ô tương ứng trên Internet Banking (Lưu ý: Vui lòng sao chép \"Nội dung đính kèm\" từ đơn nạp tiền và dán vào mục \"Mục đích\" trên trang Internet Banking)</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/minsheng5.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 6: Xác nhận thông tin nạp tiền, nhấp \"Gửi\" </strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/minsheng6.jpg\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 7: Trang thông báo giao dịch thành công</strong> \r\n</p>',1480965545),
(22,35,'Vấn đề nạp tiền','Quy trình chuyển tiền từ Ngân hàng Merchants (CMB) sang Công Thương','<p>\r\n <strong>Bước 1: Nhấp vào nút \"Trung tâm thành viên - Quản lý quỹ - Tôi muốn nạp tiền - Chuyển khoản ngân hàng trực tuyến\" trên trang chủ, chọn \"Ngân hàng Công Thương (ICBC)\", nhập số tiền, sau đó nhấp \"Tiếp theo\"</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang1.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 2: Lấy thông tin nạp tiền</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang2.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 3: Đăng nhập vào trang Internet Banking CMB, nhấp vào \"Chuyển khoản\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/zhaohang3.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 4: Chọn </strong><strong>\"Chuyển khoản liên ngân hàng\", và sử dụng tính năng sao chép, dán các thông tin như \"Tên tài khoản người nhận, Số tài khoản người nhận, Chi nhánh mở thẻ\" vào các ô tương ứng trên Internet Banking (Lưu ý: Vui lòng sao chép \"Nội dung đính kèm\" từ đơn nạp tiền và dán vào mục \"Nội dung đính kèm\" trên trang Internet Banking) </strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/zhaohang4.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 5: Xác nhận thông tin chuyển khoản</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/zhaohang5.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 6: Thông báo nạp tiền thành công</strong> \r\n</p>',1480965569),
(23,35,'Vấn đề nạp tiền','Quy trình chuyển tiền từ Ngân hàng Communications (BoCom) sang Công Thương','<p>\r\n <strong>Bước 1: Nhấp vào nút \"Trung tâm thành viên - Quản lý quỹ - Tôi muốn nạp tiền - Chuyển khoản ngân hàng trực tuyến\" trên trang chủ, chọn \"Ngân hàng Công Thương (ICBC)\", nhập số tiền, sau đó nhấp \"Tiếp theo\"</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang1.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 2: Lấy thông tin nạp tiền</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/gongshang2.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 3: Đăng nhập Internet Banking, chọn \"Chuyển sang ngân hàng khác\" dưới mục \"Chuyển khoản\", nhấp vào \"Gửi tiền\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/jiaotong3.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 4: Sao chép thông tin yêu cầu nạp tiền từ nền tảng, dán vào trang Internet Banking các thông tin như \"Số thẻ người nhận, Tên người nhận, Ngân hàng mở thẻ của người nhận, Nội dung đính kèm\" (Lưu ý: Vui lòng sao chép \"Nội dung đính kèm\" của yêu cầu nạp tiền và dán vào mục \"Nội dung gửi tiền\" trên trang Internet Banking)</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/jiaotong4.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 5: Sau khi kiểm tra thông tin, nhập \"Mã xác minh tài khoản chuyển đến\", nhấp \"Xác nhận\", nhập \"Mật khẩu usbkey\".</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/jiaotong5.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 6: Chuyển khoản thành công</strong> \r\n</p>',1480965588),
(24,35,'Vấn đề nạp tiền','Nạp tiền nhanh','<ul class=\"ul_help\" id=\"ul_help_s\">\r\n <li style=\"background-color:#fff;\">\r\n   <div class=\"hc_cont\">\r\n     <ul class=\"ul_help\" id=\"ul_help_s\">\r\n       <li style=\"background-color:#FFFFFF;\">\r\n          <div class=\"hc_cont\">\r\n           <p>\r\n             <strong>Để bảo vệ quyền lợi của thành viên và đảm bảo an toàn tiền tệ.</strong> \r\n            </p>\r\n            <p>\r\n             <strong>1. Nền tảng của chúng tôi hợp tác với các đối tác thứ ba bao gồm Alipay, YeePay, IPS, WeChat, tất cả đều có giấy phép thanh toán UnionPay.</strong> \r\n           </p>\r\n            <p>\r\n             <strong>2. Nhấp vào nạp tiền, chọn tính năng thanh toán nhanh, điền số tiền nạp tùy chọn.</strong> \r\n            </p>\r\n            <p>\r\n             <strong>3. Đăng nhập vào ngân hàng trực tuyến để thanh toán.</strong> \r\n           </p>\r\n            <p>\r\n             <strong>4. Nạp tiền thành công.</strong> \r\n           </p>\r\n          </div>\r\n        </li>\r\n     </ul>\r\n   </div>\r\n  </li>\r\n</ul>',1480965605),
(25,35,'Vấn đề nạp tiền','Nạp tiền Alipay','<p>\r\n <strong>Bước 1: Nhấp vào nút \"Trung tâm thành viên - Quản lý quỹ - Tôi muốn nạp tiền - Thanh toán nhanh\" trên trang chủ, chọn \"Alipay\", nhập số tiền, sau đó nhấp \"Tiếp theo\"</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/zfb1.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 2: Lấy thông tin nạp tiền</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/zfb2.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 3: Nhấp vào \"Đi đến Alipay nạp tiền\" để đăng nhập vào trang Alipay</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/zfb3.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 4: Vào trang chuyển tiền thanh toán, ở dòng \"Người nhận\", dán \"Số tài khoản Alipay người nhận\" và \"Tên xác minh\" đã sao chép từ nền tảng, \"Nhập số tiền nạp\" (Lưu ý: Vui lòng sao chép \"Nội dung đính kèm\" từ yêu cầu nạp tiền, dán vào mục \"Mô tả thanh toán\")</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/zfb4.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 5: Sau khi nhấp vào \"Thanh toán\", nhập \"Mật khẩu thanh toán\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/zfb5.png\" /> \r\n</p>\r\n<p>\r\n <strong>Bước 6: Thanh toán nạp tiền thành công</strong> \r\n</p>',1480965624),
(26,36,'Vấn đề mua xổ số','Quy trình mua vé số','<p>\r\n <strong>Bước 1:</strong><strong> Đăng nhập vào nền tảng, chọn loại xổ số bạn muốn đặt cược (ví dụ: K3 Giang Tô...)</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/goucai1.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 2: Vào trang đặt cược, chọn cách chơi yêu thích (như Tài Xỉu, Chẵn Lẻ), chọn số sau đó nhập \"Số tiền\", </strong> <strong>nhấp vào \"Đặt cược ngay\"</strong> \r\n</p>\r\n<p>\r\n <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/goucai2.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 3: Vui lòng kiểm tra lại để đảm bảo chính xác, sau đó nhấp [Xác nhận]</strong> \r\n</p>\r\n<p>\r\n <strong><img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/goucai3.png\" /></strong> \r\n</p>\r\n<p>\r\n <strong>Bước 4: Sau khi đặt cược thành công, nhấp vào [Lịch sử cược] để tra cứu lịch sử đặt cược</strong> \r\n</p>',1480965647),
(27,37,'Vấn đề rút tiền','Rút tiền trên nền tảng có an toàn không?','<strong>Việc gửi yêu cầu rút tiền đảm bảo chỉ Người dùng chính chủ mới có thể thao tác rút tiền; Bằng cách đối chiếu thông tin thẻ ngân hàng rút tiền mà Người dùng cung cấp với thông tin xác thực danh tính lúc Người dùng đăng ký, để đảm bảo Người dùng chỉ có thể rút tiền về thẻ ngân hàng của chính mình. Bất kỳ ai cũng không thể đánh cắp tiền của Người dùng, đảm bảo việc rút tiền là tuyệt đối an toàn.</strong>',1480965672),
(28,37,'Vấn đề rút tiền','Lưu ý khi rút tiền','<ul class=\"ul_help\" id=\"ul_help_s\">\r\n <li style=\"background-color:#fff;\">\r\n   <div class=\"hc_cont\">\r\n     <ul class=\"ul_help\" id=\"ul_help_s\">\r\n       <li style=\"background-color:#FFFFFF;\">\r\n          <div class=\"hc_cont\">\r\n           <strong>1. Trước khi rút tiền, vui lòng liên kết \"Email\" hoặc \"Số điện thoại\", đồng thời liên kết sẵn thẻ ngân hàng.&nbsp;</strong> \r\n           <p>\r\n             <strong>2. Số tiền rút phải nằm trong phạm vi hạn mức có thể rút.&nbsp;</strong> \r\n            </p>\r\n            <p>\r\n             <strong>3. Sau khi gửi yêu cầu rút tiền thành công, tiền sẽ vào tài khoản trong vòng 10 phút. Nếu do sự cố hệ thống ngân hàng trực tuyến hoặc các yếu tố bất khả kháng khác, thời gian nhận tiền sẽ bị chậm trễ. Nếu bạn có bất kỳ câu hỏi nào về việc rút tiền, bạn cũng có thể liên hệ với bộ phận CSKH trực tuyến.</strong> \r\n           </p>\r\n          </div>\r\n        </li>\r\n     </ul>\r\n   </div>\r\n  </li>\r\n</ul>',1480965692),
(29,37,'Vấn đề rút tiền','Làm thế nào để rút tiền?','<p>\r\n  <strong>Vào trang chủ nền tảng nhấp \"Trung tâm thành viên -- Quản lý quỹ -- Tôi muốn rút tiền\", chọn thẻ ngân hàng bạn muốn rút tiền về, nhập \"Mã xác minh\" của bạn rồi gửi. Đối với Người dùng đăng ký tài khoản lần đầu, vui lòng chắc chắn đã liên kết \"Email\" và \"hoặc Số điện thoại\" đồng thời \"Liên kết thẻ ngân hàng\".</strong> \r\n</p>\r\n<p>\r\n <strong><img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/qk1.png\" /></strong> \r\n</p>',1480965710),
(30,38,'Bảo mật tài khoản','Làm thế nào để đổi mật khẩu đăng nhập?','<ul class=\"ul_help\" id=\"ul_help_s\">\r\n <li style=\"background-color:#fff;\">\r\n   <div class=\"hc_cont\">\r\n     <ul class=\"ul_help\" id=\"ul_help_s\">\r\n       <li style=\"background-color:#FFFFFF;\">\r\n          <div class=\"hc_cont\">\r\n           <strong>Vui lòng vào [Trung tâm bảo mật nền tảng -- Quản lý Mật khẩu], nhập \"Mật khẩu cũ\" để sửa đổi mật khẩu đăng nhập của bạn.</strong> \r\n          </div>\r\n        </li>\r\n     </ul>\r\n   </div>\r\n  </li>\r\n</ul>',1480965738),
(31,38,'Bảo mật tài khoản','Quên tên tài khoản phải làm sao?','<ul class=\"ul_help\" id=\"ul_help_s\">\r\n <li style=\"background-color:#fff;\">\r\n   <div class=\"hc_cont\">\r\n     <ul class=\"ul_help\" id=\"ul_help_s\">\r\n       <li style=\"background-color:#FFFFFF;\">\r\n          <div class=\"hc_cont\">\r\n           <p>\r\n             <strong>Nếu quên tên tài khoản nền tảng (Tên người dùng</strong><strong>), vui lòng liên hệ CSKH nền tảng và cung cấp các thông tin liên quan để được hỗ trợ lấy lại.</strong> \r\n           </p>\r\n          </div>\r\n        </li>\r\n     </ul>\r\n   </div>\r\n  </li>\r\n</ul>',1480965763),
(32,38,'Bảo mật tài khoản','Quên mật khẩu đăng nhập phải làm sao?','<p>\r\n &nbsp;<strong>Bước 1: Vào trang đăng nhập nền tảng, nhấp vào \"Quên mật khẩu\" trên trang đăng nhập</strong> \r\n</p>\r\n<p>\r\n &nbsp;<img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/wjmm1.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 2: Nhập tên tài khoản bạn cần lấy lại mật khẩu đăng nhập và mã xác minh, sau đó nhấp \"Tiếp theo\" </strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/wjmm2.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Bước 3: Chọn phương thức bạn muốn sử dụng để khôi phục mật khẩu đăng nhập, có 3 phương thức sau để khôi phục.</strong> \r\n</p>\r\n<p>\r\n  <img alt=\"\" src=\"http://www.k399.com/templates/SSC/images/bzzx/wjmm3.png\" /> \r\n</p>\r\n<p>\r\n  <strong>Nếu</strong><strong> các phương thức trên đều không khả dụng? Bạn cũng có thể thông qua CSKH trực tuyến để khiếu nại nhân công lấy lại mật khẩu đăng nhập</strong>。\r\n</p>',1480965940),
(33,39,'Quy tắc giới hạn cách chơi','Giới hạn số vé cược và giải thích thiết lập tiền thưởng tối đa','<ul class=\"ul_help\" id=\"ul_help_s\">\r\n <li style=\"background-color:#fff;\">\r\n   <div class=\"hc_cont\">\r\n     <ul class=\"ul_help\" id=\"ul_help_s\">\r\n       <li style=\"background-color:#FFFFFF;\">\r\n          <div class=\"hc_cont\">\r\n           <p>\r\n             <strong>Nền tảng này có giới hạn cách chơi, nghiêm cấm mọi hành vi gian lận bào hoa hồng, nền tảng sẽ giám sát theo thời gian thực đối với các hành vi này.</strong> \r\n            </p>\r\n            <p>\r\n             <strong>Giới hạn cách chơi: Đánh 5 sao lớn hơn 80.000 vé cược, 4 sao lớn hơn 8.000 vé, 3 sao lớn hơn 800 vé, 2 sao lớn hơn 80 vé, lô định vị lớn hơn 8 số đều bị xử lý như gian lận, trường hợp nghiêm trọng sẽ bị khóa tài khoản.&nbsp;</strong> \r\n           </p>\r\n            <p>\r\n             <strong>Tiền thưởng tối đa cho mỗi đơn cược là 200.000,00 VNĐ (Quy đổi), nếu vượt quá sẽ tính là 200.000,00 VNĐ</strong><strong>, phần tiền thưởng vượt quá sẽ bị reset về 0;</strong> \r\n            </p>\r\n            <p>\r\n             <strong>Chọn thẳng 5 sao từ 1024 vé trở xuống, chọn thẳng 4 sao 81 vé, chọn thẳng 3 sao 8 vé, chọn thẳng 2 sao 4 vé trở xuống, nhóm ba 2 vé, nhóm sáu 4 vé trở xuống đều được liệt vào chế độ đánh đơn (solo mode). Tiền thưởng tối đa cho mỗi kỳ ở chế độ đánh đơn là 10.000,00 VNĐ, nếu vượt quá sẽ trả lại 10.000,00 VNĐ, vui lòng lưu ý kỹ điều này</strong> \r\n            </p>\r\n          </div>\r\n        </li>\r\n     </ul>\r\n   </div>\r\n  </li>\r\n</ul>',1480965965),
(34,40,'Mẹo và Chiến lược K3','Mẹo cá cược và chiến lược thực chiến K3: Phương pháp theo dõi quỹ đạo bóng ra','Chia sẻ bí kíp độc quyền K3 mới: Phương pháp theo dõi quỹ đạo bóng ra&nbsp;&nbsp; \r\nPhương pháp theo dõi quỹ đạo bóng ra chủ yếu tham khảo \"Biểu đồ thứ tự xếp bóng gốc K3\". Các số trúng thưởng K3 được phân bổ theo chiều dọc, chiều ngang, hình tam giác, hoặc theo hướng chéo trong biểu đồ thứ tự xếp bóng. Dựa trên 3 yếu tố xu hướng này, chọn ra những số có đặc điểm rõ ràng trong \"Vị trí đặt bóng hàng trăm\", \"Vị trí đặt bóng hàng chục\", \"Vị trí đặt bóng hàng đơn vị\" để đặc biệt quan tâm.<br />\r\n\"Phương pháp theo dõi quỹ đạo bóng ra\" lấy \"vị trí đặt bóng\" làm điểm tựa để nghiên cứu. Góc độ này mới mẻ, khác với \"Số thử máy\" và \"Số bóng máy\" mà chúng ta thường tham khảo hàng ngày, và nó khá chính xác. Vị trí đặt bóng chính là vị trí của các quả bóng trong lồng quay thưởng, không có thứ tự cố định.<br />\r\nNgoài \"Phương pháp theo dõi quỹ đạo bóng ra\", một thành quả nghiên cứu khác của chuyên gia bình luận xổ số đặc biệt của báo chúng tôi, Li Yuqun, đó là \"Biểu đồ phân bổ số xuất hiện/không xuất hiện trong 3 kỳ trước\". Nghĩa là dãy số kỳ này đã xuất hiện bao nhiêu lần trong 3 kỳ trước đó, việc có hay không có trong 3 kỳ được phân bổ có quy luật trong biểu đồ. Nếu người chơi có thể đoán chính xác dãy số hiện tại sẽ chứa bao nhiêu số trong 3 kỳ trước, phạm vi đặt cược sẽ được thu hẹp đáng kể. Sau khi được báo chúng tôi áp dụng, biểu đồ phân bổ này đã tạo ra tiếng vang lớn trong giới người chơi xổ số, những người chơi mới có thể chú ý theo dõi.',1480965984),
(35,40,'Mẹo và Chiến lược K3','Đề xuất mẹo đặt cược K3: Dạy bạn tìm bí ẩn chọn số từ công thức','Tại trạm bán vé số, có vài người chơi đang vò đầu bứt tai suy nghĩ xem nên chọn số nào để cược. Có người ngẩng đầu nhìn biểu đồ xu hướng trong trạm, có người nhìn chằm chằm vào màn hình hiển thị số mở thưởng. Họ đều là những người đam mê trò chơi K3, một trò chơi mở thưởng mỗi 10 phút/kỳ khiến họ không thể rời mắt. Chủ trạm xổ số thấy mọi người đau đầu việc chọn số, bèn tiến đến chia sẻ một vài mẹo nhỏ mà mình biết.<br />\r\n&nbsp;<br />\r\nTrong \"K3\", nếu không phân biệt vị trí, cùng một số xuất hiện liên tiếp 3 hoặc 4 kỳ đã là giới hạn cực điểm. Khi một số nào đó xuất hiện liên tiếp 4 kỳ (không phân biệt vị trí), ở kỳ tiếp theo chắc chắn sẽ không có ai chọn số đó nữa. Tuy nhiên, cơ hội \"loại số (kill number)\" này không nhiều, một năm cũng chỉ có vài lần xuất hiện liên tiếp 4 kỳ, vì vậy mọi người luôn tìm kiếm cơ hội cực điểm này. \"Phương pháp công thức\" ra đời từ đó, ngay khi xuất hiện nó đã được người chơi xổ số hoan nghênh và săn đón.<br />\r\n&nbsp;<br />\r\nCông thức 1:<br />\r\n&nbsp;<br />\r\n\"Công thức loại số\" trong \"K3\" như sau: Lấy số thứ 3 của giải mở thưởng kỳ hiện tại × 2 + 4, kết quả đem chia cho 10 lấy số dư. Số dư này chính là con số có khả năng cao sẽ ra ở \"kỳ tiếp theo\"!<br />\r\n&nbsp;<br />\r\nCông thức 2:<br />\r\n&nbsp;<br />\r\nSố mở thưởng kỳ hiện tại: Số thứ 3 × 3 + 3, kết quả đem chia cho 10 lấy số dư. Số dư này chính là con số có khả năng cao sẽ ra ở \"kỳ tiếp theo\"!',1480966010),
(36,40,'Mẹo và Chiến lược K3','Mẹo cá cược và chiến lược thực chiến K3: Ba nguyên tắc cược Tổng điểm (Hòa giá trị)','Thực tiễn mang lại kiến thức đích thực. Khi những người chơi xổ số áp dụng một lượng lớn các phương pháp để đặt cược K3, cuối cùng họ đưa ra một kết luận: sử dụng tổng điểm để đặt cược \"K3\" là một trong những phương tiện quan trọng để tăng tỷ lệ trúng thưởng. Để tăng thêm tỷ lệ trúng thưởng, chúng tôi đã đúc kết \"Ba nguyên tắc\" để lựa chọn chính xác giá trị tổng của dàn 3 số:<br />\r\nNguyên tắc 1: Tổng điểm liền kề đã ra hay chưa. Nếu chúng ta chọn tổng điểm 13 để cược, trước tiên phải xem các tổng điểm liền kề với 13, tức là 12 và 14 đã từng ra hay chưa. Nếu đã ra, có thể cân nhắc đặt cược. Nếu tổng điểm 12 và 14 đã xuất hiện, kỳ tiếp theo có khả năng cao sẽ ra số ở giữa của 12 và 14, tức là tổng điểm 13. Nếu không, nên từ bỏ.<br />\r\nNguyên tắc 2: Tổng điểm cùng đuôi đã ra hay chưa. Nếu chúng ta chọn tổng điểm 13 để cược, phải xem tổng điểm cùng đuôi với 13, tức là 3 hoặc 23 đã ra hay chưa. Nếu đã ra, có thể cân nhắc đặt cược. Ở đây, chúng ta có thể coi các tổng điểm 3 hoặc 23 đã mở thưởng như một \"Khúc dạo đầu\" của tổng điểm 13. Ở kỳ tiếp theo, rất có khả năng sẽ mở ra tổng điểm 13 như một \"Khúc hòa tấu\". Nếu không, nên từ bỏ. Phải vận dụng tổng hợp \"Ba nguyên tắc\" này thì mới nhận được hiệu quả rõ rệt, tuyệt đối không được đánh lẻ, tách rời khi sử dụng.<br />\r\nNguyên tắc 3: Đã đạt đến khoảng cách nhịp trung bình hay chưa. Lấy tổng điểm 13 làm ví dụ, kể từ khi \"K3\" chính thức mở thưởng độc lập, tính đến kỳ 05018, tổng điểm 13 đã xuất hiện tổng cộng 14 lần, số kỳ cách nhau lần lượt là: 8, 11, 2, 13, 2, 2, 17, 12, 18, 3, 20, 0, 26, 1. Tổng số kỳ khoảng cách là 135 kỳ, số kỳ khoảng cách trung bình xấp xỉ 10 kỳ. Khi quyết định sử dụng tổng điểm để cược, chúng ta phải xem tổng điểm 13 đã hơn 10 kỳ chưa ra hay chưa. Nếu đã đạt đến mức đó, có thể cân nhắc đặt cược; Nếu chưa đạt, nên từ bỏ.',1480966029),
(37,40,'Mẹo và Chiến lược K3','Giải thích chi tiết chiến lược K3: Tâm lý rất quan trọng, Đừng quên ba chữ Tâm','K3 là một loại hình xổ số mở thưởng nhanh, đặc điểm mở thưởng ngay lập tức cho phép người chơi tận hưởng nhiều niềm vui khi mua xổ số. Tuy nhiên, dù trúng hay trượt, mua K3 đòi hỏi phải liên tục điều chỉnh tâm lý, kiểm soát tốt cường độ mua. Bằng cách này, dù kết quả thế nào, đó cũng là một trải nghiệm chơi xổ số thành công. Vậy nên điều chỉnh tâm lý như thế nào? Biên tập viên cho rằng \"Ba chữ Tâm\" rất quan trọng!<br />\r\nTâm \"Chơi\": Bình tâm đối xử với việc phát hành và mua xổ số lâu dài bằng một tâm lý lành mạnh. Có thể bình tĩnh nhìn nhận \"Xổ số\", duy trì cảm xúc bình thường, không biến động lớn. Coi mua xổ số là một trò chơi, không tham gia cá cược mạo hiểm, chủ yếu là để \"chơi\" tìm niềm vui, thêm màu sắc cho cuộc sống; Đặt cược tùy theo khả năng, tuyệt đối không ảnh hưởng đến cuộc sống sinh hoạt. Không dao động cảm xúc nhiều dù trúng hay trượt, trúng giải lớn không quá mừng rỡ hay phát cuồng để phòng ngừa niềm vui tột độ hóa nỗi buồn; Liên tục đánh trượt cũng không hối hận hay phàn nàn, hãy coi đó là một sự \"cống hiến\".<br />\r\nTâm \"Kiên\": Kiên tâm mua xổ số, theo sát từng kỳ, tuyệt đối không gián đoạn nếu không có lý do đặc biệt. Đừng học theo một số người chơi, hứng lên thì đánh, trượt thì dừng, bỏ dở giữa chừng; Cũng đừng vì trúng giải nhỏ mà tăng tiền cược lên cao, càng không nên vì liên tục trượt mà than vãn đến mức ngừng mua xổ số. Phải coi việc mua xổ số là cơ hội tốt để rèn luyện sự kiên trì, duy trì bền bỉ, nước chảy đá mòn, tìm niềm vui trong việc chơi xổ số lâu dài và chờ đón tài lộc.<br />\r\nTâm \"Học\": Khi chọn số phải có tâm \"Học\", học hỏi các phương pháp và kỹ năng cá cược khác nhau của người khác. Tận hưởng niềm vui trong quá trình nghiên cứu, làm phong phú thêm ý nghĩa cuộc sống, quan trọng hơn là đúc kết lại được mất trong cách cược của bản thân, tìm ra bí quyết từ những điều không có quy luật, tìm kiếm phương pháp cược tốt hơn. Người chơi lớn tuổi càng cần phải \"học\", thông qua việc \"học\" chơi xổ số để thúc đẩy quá trình trao đổi chất của tế bào não, rèn luyện trí não linh hoạt, đạt được mục đích kéo dài tuổi thọ. Thế giới xổ số cũng muôn màu muôn vẻ như cuộc đời.',1480966047),
(38,40,'Mẹo và Chiến lược K3','Mẹo đặt cược K3: Cao thủ hướng dẫn bạn cách chơi dạng 3 số giống nhau (Bão)','Cược 3 số giống nhau bao gồm 2 cách chơi: Chọn tất cả 3 số giống nhau (Bão bất kỳ) và Chọn 3 số giống nhau cụ thể (Bão duy nhất). Trong đó, cách Chọn tất cả 3 số giống nhau tương đối đơn giản, chỉ với 2 tệ bạn có thể bao toàn bộ Bão (111, 222, 333, 444, 555, 666) để cược. Trong các số mở thưởng, chỉ cần ra bất kỳ bộ Bão nào là trúng thưởng. Chọn 3 số giống nhau cụ thể là chọn tùy ý một bộ số trong tất cả các bộ 3 số giống nhau (111, 222, 333, 444, 555, 666) để cược, cách chơi này tương đối khó hơn nhưng tiền thưởng tương ứng cũng cao hơn.<br />\r\nDưới đây là tổng hợp một số mẹo thường dùng của các cao thủ khi chơi K3, hy vọng sẽ giúp ích cho mọi người.<br />\r\nI. Theo dõi nhịp gan (Số chưa về)<br />\r\nChu kỳ gan của một bộ 3 số giống nhau tương đối dài, hiện tại kỷ lục gan lâu nhất là tổ hợp 111 với 1260 kỳ. Mặc dù tiền thưởng cho 3 số giống nhau cụ thể rất cao, nhưng rủi ro cũng lớn. Do đó, phải theo dõi 3 số giống nhau tùy theo thời cơ. Bạn có thể dựa vào xu hướng gần đây, giả sử trong 30 kỳ qua chưa ra, thì có thể thông qua biểu đồ phân bố 56 số để so sánh số lần ra của 6 bộ 3 số giống nhau trong một tháng. Bỏ đi bộ lạnh nhất (ít ra nhất), bộ ra nhiều lần nhất, và 3 bộ ra ít nhất. 3 bộ 3 số giống nhau còn lại dùng làm kế hoạch nuôi trong 40 kỳ, thiết kế lợi nhuận hợp lý dựa trên điều kiện tài chính của bản thân, trong nhiều trường hợp bạn sẽ thu hoạch được kết quả tốt.<br />\r\nNếu bạn cảm thấy chọn 3 số giống nhau cụ thể quá khó, sợ dù có ra Bão cũng chưa chắc là bộ bạn chọn, thì việc chọn nuôi bao tất cả Bão sẽ an toàn hơn. Chỉ cần ra Bão trong chu kỳ bạn nuôi là có lãi. Tất nhiên, biên tập viên cũng phải nhắc nhở mọi người rằng, trong tình huống ra Bão liên tục trong 21 ngày gần đây, việc nuôi bao tất cả Bão cũng tiềm ẩn rủi ro, vì một số nóng quá lâu cũng sẽ có lúc lạnh. Bạn cũng có thể chọn bắt đầu sử dụng phương pháp này để lên kế hoạch nuôi Bão cụ thể hoặc bao Bão vào ngày thứ 3 sau khi Bão đã đi vào dây lạnh, nhằm nâng cao tỷ lệ trúng.<br />\r\nII. Sử dụng Tổng điểm (Hòa giá trị) để chọn số<br />\r\nTrong K3, các mức Tổng điểm bao gồm tổ hợp 3 số giống nhau lần lượt là: 3(111), 6(222), 9(333), 12(444), 15(555), 18(666). Trong đó 9 và 12 có tần suất xuất hiện cao hơn, còn 3 và 18 có tiền thưởng cao nhất nhưng xác suất ra thấp nhất. Do đó, có thể tập trung chú ý vào một vài Tổng điểm ở khoảng giữa có tần suất cao để tiến hành chọn số, đặt cược Bão cụ thể.<br />\r\nIII. Kết hợp số rơi và số nóng<br />\r\nQuan sát các số mở thưởng của 10 kỳ gần nhất, có thể sử dụng kết hợp số nóng và số rơi để chọn số cược Bão cụ thể. Từ biểu đồ có thể thấy, sau khi số nóng 1 xuất hiện liên tiếp 3 kỳ, đến kỳ thứ 72 đã ra bộ Bão 111.<br />\r\nNhịp gan lý thuyết của việc bao tất cả Bão là 1/36. Khi số kỳ gan của tính năng bao tất cả Bão đạt khoảng gấp đôi so với nhịp gan lý thuyết, bạn có thể kết hợp với tình hình ra Bão của 2 ngày gần đây để lên kế hoạch nuôi số. Đáng chú ý là, kỷ lục nhịp gan lịch sử của bao tất cả Bão là 317 kỳ.',1480966068),
(43,33,'Hướng dẫn trợ giúp','Cách đăng ký','<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n <span style=\"font-size:12px;\">Nhấp vào nút \"Đăng ký Người dùng\" ở góc trên bên phải trang web là có thể vào trang đăng ký Người dùng;</span>\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n Làm theo hướng dẫn, điền thông tin đăng ký là có thể hoàn tất <span style=\"font-size:12px;\">đăng ký</span>;\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n Tài khoản dài 4-15 ký tự, hỗ trợ số và chữ cái, không được bắt đầu bằng số 0;\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n Mật khẩu dài 6-16 ký tự, hỗ trợ số, chữ cái và ký tự đặc biệt;\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n  Sau khi đăng ký hoàn tất, hệ thống sẽ phân bổ ngẫu nhiên một Ảnh đại diện. Vào \"Tài khoản của tôi\" -> \"Thông tin cá nhân\" để có thể sửa đổi Ảnh đại diện và cài đặt Biệt danh;\r\n</p>',1494640149),
(44,33,'Hướng dẫn trợ giúp','Thời gian phục vụ của CSKH trực tuyến','<span style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\"><span style=\"font-weight:bolder;font-family:\" font-size:12px;\"=\"\">CSKH trực tuyến của nền tảng cung cấp dịch vụ chuyên nghiệp và chất lượng cao nhất cho bạn từ </span></span><span style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\"><span style=\"font-weight:bolder;font-family:\" font-size:12px;\"=\"\">00:00 rạng sáng - 23:59 đêm.</span></span><span style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\"><span style=\"font-weight:bolder;font-family:\" font-size:12px;\"=\"\"> Các khung giờ khác, vui lòng để lại thông tin liên hệ và câu hỏi của bạn, chúng tôi sẽ liên hệ xử lý giúp bạn trong thời gian sớm nhất.</span></span><span style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\"><span style=\"font-weight:bolder;font-family:\" font-size:12px;\"=\"\"> Tôn chỉ phục vụ của nền tảng: Chúng tôi chuyên nghiệp, bạn yên tâm; Chúng tôi tận tụy, bạn an tâm.</span></span>',1494640774),
(45,33,'Hướng dẫn trợ giúp','Các phương thức nạp tiền của nền tảng là gì?','<p style=\"font-family:微软雅黑, &quot;font-size:14px;background-color:#FFFFFF;color:#666666;\">\r\n  <span style=\"font-family:Tahoma;\">Hiện tại trang web cung cấp bốn phương thức nạp tiền, đó là: \"Chuyển khoản ngân hàng trực tuyến, Nạp tiền nhanh, Nạp tiền WeChat và Nạp tiền Alipay\".</span>\r\n</p>\r\n<p style=\"font-family:微软雅黑, &quot;font-size:14px;background-color:#FFFFFF;color:#666666;\">\r\n <span style=\"font-family:Tahoma;\">Chuyển khoản ngân hàng trực tuyến: Chỉ việc thông qua Internet Banking, gửi tiền tại quầy v.v. để chuyển tiền vào tài khoản ngân hàng do trang web cung cấp;</span>\r\n</p>\r\n<p style=\"font-family:微软雅黑, &quot;font-size:14px;background-color:#FFFFFF;color:#666666;\">\r\n <span style=\"font-family:Tahoma;\">Nạp tiền nhanh: Thanh toán thông qua bên thứ ba, thuận tiện và nhanh chóng;</span>\r\n</p>\r\n<p style=\"font-family:微软雅黑, &quot;font-size:14px;background-color:#FFFFFF;color:#666666;\">\r\n <span style=\"font-family:Tahoma;\">Nạp tiền Alipay: Chỉ việc thông qua chuyển khoản Alipay vào tài khoản Alipay do trang web cung cấp.</span>\r\n</p>\r\n<p style=\"font-family:微软雅黑, &quot;font-size:14px;background-color:#FFFFFF;color:#666666;\">\r\n <span style=\"font-family:Tahoma;\">Nạp tiền WeChat: Chỉ việc thông qua chuyển khoản WeChat vào tài khoản WeChat do trang web cung cấp.</span>\r\n</p>',1494640796),
(46,33,'Hướng dẫn trợ giúp','Cách mua xổ số','<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n <span style=\"font-family:&quot;font-size:12px;\">Trước khi mua xổ số cần phải nạp tiền, tài khoản có Số dư mới có thể tiến hành đặt cược mua xổ số;</span>\r\n</p>\r\n<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n  Sau khi nạp tiền hoàn tất, bạn có thể vào \"Sảnh xổ số\" để chọn loại xổ số mình thích và tiến hành đặt cược;\r\n</p>\r\n<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n  Trang đặt cược xổ số cung cấp \"Hướng dẫn cách chơi\" và \"Biểu đồ xu hướng\", có thể giúp bạn nhanh chóng hiểu rõ \"Quy tắc cách chơi\" và \"Xu hướng mở thưởng\"\r\n</p>\r\n<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n  Sau khi đặt cược thành công, bạn có thể vào \"Tài khoản của tôi\" -> \"Lịch sử đặt cược\" để xem chi tiết các cược của mình, và xem có trúng thưởng hay không;\r\n</p>\r\n<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n  Sau khi đặt cược, cần phải chờ sau khi mở thưởng mới có thể kiểm tra xem có trúng hay không;\r\n</p>\r\n<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n  Sau khi đặt cược thành công, hệ thống sẽ tự động trừ số tiền cược tương ứng từ Số dư tài khoản của bạn. Nếu trúng thưởng, tiền thưởng sẽ tự động được cộng vào Số dư tài khoản của bạn;\r\n</p>\r\n<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n <span style=\"font-family:&quot;font-size:12px;\">Có thể vào \"Tài khoản của tôi\" -> \"Lịch sử giao dịch\" để xem chi tiết giao dịch tài khoản của bạn;</span>\r\n</p>',1494640853),
(47,33,'Hướng dẫn trợ giúp','Cách rút tiền','<p style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\">\r\n <span style=\"font-family:\" font-size:12px;\"=\"\">Rút tiền sau khi trúng thưởng như thế nào? Nhấp vào nút \"Rút tiền\" ở góc trên bên phải trang web để vào trang rút tiền;</span> \r\n  </p>\r\n<p style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\">\r\n  Chọn thẻ ngân hàng bạn đã liên kết, điền Số tiền bạn muốn rút, và nhập \"Mật khẩu an toàn\";\r\n</p>\r\n<p style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\">\r\n Sau khi gửi đơn yêu cầu rút tiền, khoảng 1-3 phút tiền sẽ vào tài khoản, bạn có thể đăng nhập vào ứng dụng ngân hàng để kiểm tra số dư;\r\n  </p>\r\n<p style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\">\r\n  Nhấp \"Tài khoản của tôi\" -> \"Lịch sử giao dịch\" có thể xem chi tiết giao dịch hàng ngày;\r\n</p>\r\n<p style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\">\r\n  <span style=\"font-family:\" font-size:12px;\"=\"\">Trước khi rút tiền cần phải thiết lập </span><span style=\"font-family:\" font-size:12px;\"=\"\">\"Mật khẩu an toàn</span><span style=\"font-family:\" font-size:12px;\"=\"\">\" và liên kết thẻ ngân hàng mà bạn muốn sử dụng để nhận tiền;</span> \r\n  </p>\r\n<p style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\">\r\n  Số tiền rút không được lớn hơn Số tiền có thể rút;\r\n</p>\r\n<p style=\"font-family:\" font-size:14px;color:#666666;background-color:#ffffff;\"=\"\">\r\n  Để cung cấp trải nghiệm dịch vụ tốt hơn, giảm thời gian xử lý đơn rút tiền của đông đảo Người dùng, mỗi ngày chỉ cho phép rút tối đa 3 lần, khuyến nghị Người dùng sắp xếp hợp lý thời gian và số lần rút tiền hàng ngày của mình;\r\n </p>',1494640874),
(48,33,'Hướng dẫn trợ giúp','Cách mua xổ số trên Ứng dụng điện thoại','<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n <span style=\"font-family:&quot;font-size:12px;\">Chỉ cần nhập địa chỉ trang web trực tiếp trên trình duyệt điện thoại để đăng nhập vào phiên bản Di động, không cần tải xuống ứng dụng;</span>\r\n</p>\r\n<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n Phiên bản Di động <span style=\"font-family:&quot;font-size:12px;\">cho phép bạn đặt cược mọi lúc mọi nơi, </span>tiện lợi hơn rất nhiều, chúng tôi khuyên người dùng nên sử dụng Phiên bản Di động để đặt cược;\r\n</p>\r\n<p style=\"font-family:&quot;font-size:14px;color:#666666;background-color:#FFFFFF;\">\r\n Khuyên dùng trình duyệt \"Google Chrome\", \"Safari (Apple)\", \"UC Browser\" để có trải nghiệm thao tác mượt mà hơn;\r\n</p>',1494640891),
(49,33,'Hướng dẫn trợ giúp','Bảo mật tài khoản','<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n  Vì sự an toàn tài khoản của đông đảo Người dùng, \"Trung tâm bảo mật\" của trang web cung cấp nhiều tính năng để nâng cao hệ số an toàn cho tài khoản;\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n  Sau khi người dùng mới hoàn tất đăng ký, vui lòng nhanh chóng vào \"Trung tâm bảo mật\" để liên kết \"Số điện thoại bảo mật\"<span style=\"font-size:12px;\">, \"</span>Câu hỏi bảo mật\", \"Email bảo mật\";\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n Khi Người dùng quên Mật khẩu, có thể khôi phục Mật khẩu thông qua các tính năng trên;\r\n</p>',1494640907),
(51,33,'Hướng dẫn trợ giúp','Cách liên kết thẻ ngân hàng','<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n  <span style=\"font-size:12px;\">Vào </span><span style=\"font-size:12px;\">\"Tài khoản của tôi\" -> </span><span style=\"font-size:12px;\">\"Quản lý thẻ ngân hàng\" để có thể liên kết thẻ ngân hàng mà bạn muốn dùng để rút tiền;</span>\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n <span style=\"font-size:12px;\">Trước khi liên kết thẻ ngân hàng, cần phải thiết lập mật khẩu an toàn trước;</span>\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n Mỗi người chỉ được liên kết tối đa 5 thẻ ngân hàng;\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n Hỗ trợ liên kết thẻ của tất cả các ngân hàng phổ biến hiện nay;\r\n</p>\r\n<p style=\"font-size:14px;color:#666666;background-color:#FFFFFF;font-family:&quot;\">\r\n  Vì sự an toàn vốn của Người dùng, thẻ ngân hàng đã được sử dụng rút tiền thành công sẽ tự động bị khóa, không thể xóa hay sửa đổi. Nếu bạn muốn hủy bỏ thẻ ngân hàng, vui lòng liên hệ với bộ phận CSKH trực tuyến để vô hiệu hóa thẻ đó;\r\n</p>',1494640956),
(52,33,'Hướng dẫn trợ giúp','Khung giờ rút tiền của nền tảng','<span style=\"color:#666666;font-family:\" font-size:14px;background-color:#ffffff;\"=\"\"><span style=\"font-weight:bolder;font-family:\" color:#666666;background-color:#ffffff;\"=\"\"><span style=\"font-family:SimSun;font-size:18px;\">Khung giờ rút tiền là từ 00:00 rạng sáng --- 23:59 đêm mỗi ngày</span></span></span>',1494641014),
(53,33,'Hướng dẫn trợ giúp','Quy tắc trò chơi','<p style=\"font-family:微软雅黑;font-size:12px;color:#333333;background-color:#FFFFFF;\">\r\n <span style=\"font-weight:bolder;font-family:;\"><span style=\"font-size:14px;color:#000000;\">Kết quả mở thưởng K3 trên nền tảng này được căn cứ theo kết quả mở thưởng của K3 Giang Tô, K3 Quảng Tây, K3 Cát Lâm, K3 Hồ Bắc, K3 Hà Bắc, K3 An Huy. Ngoài ra thành viên có thể cược Lẻ, Chẵn, Tài, Xỉu. Chi tiết quy tắc như sau:</span></span> \r\n</p>\r\n<p style=\"font-family:微软雅黑;font-size:12px;color:#333333;background-color:#FFFFFF;\">\r\n  <span style=\"font-weight:bolder;\"><br />\r\n</span>\r\n</p>\r\n<p style=\"font-family:微软雅黑;font-size:12px;color:#333333;background-color:#FFFFFF;\">\r\n  <span style=\"font-weight:bolder;\">Điều 1 &nbsp; Đặt cược trò chơi K3 là lấy tổ hợp ba con số làm một vé cược để tiến hành cược đơn. Mỗi số cược là một số tự nhiên bất kỳ từ 1 đến 6. Một nhóm kết hợp 3 số được gọi là một vé cược. Người mua có thể cược nhiều vé cho bộ số mình đã chọn. Không có giới hạn tối đa cho số tiền cược của một vé cược.</span>\r\n</p>\r\n<h3 style=\"font-family:微软雅黑;font-size:12px;color:#333333;background-color:#FFFFFF;\">\r\n <span style=\"font-weight:bolder;font-family:;\"> Điều 2 &nbsp; Người mua đặt cược trực tuyến. Dãy số đặt cược được ghi nhận dựa trên chứng từ mở thưởng của Giang Tô, khi mở thưởng hệ thống sẽ tự động quyết toán vào tài khoản.</span>\r\n</h3>\r\n<h3 style=\"font-family:微软雅黑;font-size:12px;color:#333333;background-color:#FFFFFF;\">\r\n <span style=\"font-weight:bolder;font-family:;\"> Điều 3 &nbsp; Trò chơi K3 dựa trên sự kết hợp của các con số, được chia thành các phương thức cược: \"Tổng điểm (Hòa giá trị)\", \"Ba số giống nhau (Bão)\", \"Hai số giống nhau\", \"Ba số khác nhau\", \"Hai số khác nhau\", \"Ba số liên tiếp chọn hết (Bao trọn bộ số liên tiếp)\", các quy định cụ thể như sau:<br />\r\n(I) Cược Tổng điểm (Hòa giá trị): Là cược tổng của 3 con số, bao gồm cược từ \"Tổng 3\" đến \"Tổng 18\".<br />\r\n(II) Cược Ba số giống nhau (Bão): Là cược vào 3 con số giống hệt nhau, được chia cụ thể thành:<br />\r\n1. Chọn bao trọn 3 số giống nhau: Là đặt cược vào tất cả các trường hợp 3 số giống nhau (111, 222, ..., 666);<br />\r\n2. Chọn 3 số giống nhau cụ thể (Bão duy nhất): Là chọn tùy ý một bộ số trong tất cả các bộ 3 số giống nhau (111, 222, ..., 666) để đặt cược.<br />\r\n(III) Cược Hai số giống nhau: Là cược vào 2 số giống nhau được chỉ định, được chia cụ thể thành:<br />\r\n1. Cược cặp 2 số giống nhau (Phức hợp): Là chọn 2 số giống nhau được chỉ định và một số bất kỳ trong số 3 con số để đặt cược;<br />\r\n2. Cược cặp 2 số giống nhau (Đơn): Là chọn 2 số giống nhau được chỉ định và một số khác biệt được chỉ định trong số 3 con số để đặt cược.<br />\r\n(IV) Cược Ba số khác nhau: Là cược vào 3 con số hoàn toàn khác nhau.<br />\r\n(V) Cược Hai số khác nhau: Là chọn 2 số khác nhau được chỉ định và một số bất kỳ để đặt cược.<br />\r\n(VI) Cược bao trọn 3 số liên tiếp (Sảnh): Là cược vào tất cả các trường hợp 3 số liên tiếp nhau (Chỉ giới hạn ở: 123, 234, 345, 456).</span> \r\n</h3>\r\n<h3 style=\"font-family:微软雅黑;font-size:12px;color:#333333;background-color:#FFFFFF;\">\r\n  <span style=\"font-weight:bolder;font-family:;\"><span style=\"font-size:14px;color:#000000;\"></span></span> \r\n</h3>\r\n<h1 style=\"font-size:12px;font-family:微软雅黑;color:#333333;background-color:#FFFFFF;\">\r\n <span style=\"font-weight:bolder;font-family:;\"><span style=\"font-size:14px;color:#E53333;\">Nếu chưa rõ về những điều trên, vui lòng liên hệ CSKH! Xin cảm ơn sự hợp tác của bạn!</span></span> \r\n</h1>\r\n<br />\r\n<p>\r\n  <br />\r\n</p>',1494641056),
(56,30,'Giới thiệu trang web','Liên hệ với chúng tôi 222','<p style=\"color:#666666;font-family:\" microsoft=\"\" yahei\"=\"\" !important;font-size:14px;background-color:#ffffff;\"=\"\"> <span style=\"font-size:12px;\">Quan Min Xing Cai hiện tại chỉ cung cấp dịch vụ tư vấn trực tuyến, nhấp vào \"CSKH trực tuyến</span><span style=\"font-size:12px;\">\" ở góc trên bên phải trang web để tiến hành tư vấn trực tuyến; hoặc kết bạn với QQ CSKH:</span> \r\n  </p>\r\n<p style=\"color:#666666;font-family:\" microsoft=\"\" yahei\"=\"\" !important;font-size:14px;background-color:#ffffff;\"=\"\"> <span style=\"font-size:12px;\"><span>Chúng tôi cung cấp dịch vụ tư vấn trực tuyến 16 tiếng một ngày, từ 8 giờ sáng đến 12 giờ đêm, hoạt động xuyên suốt cả năm không nghỉ;</span> Đội ngũ CSKH chuyên nghiệp, túc trực 16 tiếng để giải đáp mọi thắc mắc của bạn;</span> \r\n</p>',1495071988),
(58,30,'Giới thiệu trang web','Tuyên bố pháp lý','<span style=\"color:#666666;font-family:\'Microsoft YaHei\';font-size:14px;line-height:24px;background-color:#FFFFFF;\">Bản quyền của bất kỳ nội dung nào (bao gồm nhưng không giới hạn ở dữ liệu, văn bản, biểu đồ, hình ảnh, âm thanh hoặc video, v.v.) được cung cấp trên trang web này đều thuộc về trang web này hoặc các chủ sở hữu quyền liên quan. Nếu không có sự cho phép trước bằng văn bản của trang web này hoặc các chủ sở hữu quyền liên quan, bạn không được phép tự ý sao chép, tái tạo, phát tán, xuất bản, đăng lại, chỉnh sửa hoặc trưng bày nội dung của trang web này dưới bất kỳ hình thức nào. Đồng thời, nếu không có sự cho phép bằng văn bản của trang web này, bất kỳ ai cũng không được tạo bản sao trên các máy chủ không thuộc về trang web này đối với bất kỳ nội dung nào trên trang web. Bất kỳ hành vi sử dụng nội dung trái phép nào trên trang web này đều vi phạm "Luật Bản quyền của Cộng hòa Nhân dân Trung Hoa" và các luật, quy định khác cũng như các quy định của công ước quốc tế có liên quan.</span>',1495072059),
(59,30,'Giới thiệu trang web','Tuyên bố quyền riêng tư','<p style=\"font-size:14px;color:#666666;font-family:\'Microsoft YaHei\' !important;background-color:#FFFFFF;\">\r\n  Việc bạn cung cấp thông tin cá nhân cho chúng tôi khi đăng nhập dựa trên sự tin tưởng dành cho chúng tôi và chúng tôi sẽ đối xử với thông tin cá nhân của bạn một cách chuyên nghiệp, cẩn trọng và có trách nhiệm. Chúng tôi tin rằng quyền riêng tư là quyền quan trọng của bạn và chúng tôi tôn trọng quyền riêng tư của bạn. Thông tin bạn cung cấp chỉ được sử dụng để giúp chúng tôi cung cấp cho bạn những dịch vụ tốt hơn. Vì vậy, chúng tôi đã xây dựng hệ thống bảo mật thông tin cá nhân để bảo vệ thông tin cá nhân của bạn. Bất kỳ ai đăng nhập vào trang web này bằng bất kỳ cách nào hoặc trực tiếp hay gián tiếp sử dụng dữ liệu trên trang web này đều được coi là tự nguyện chấp nhận các ràng buộc trong tuyên bố của trang web. Các điều khoản bảo vệ quyền riêng tư của chúng tôi như sau:\r\n</p>\r\n<span style=\"line-height:24px;color:#333333;font-family:\'Microsoft YaHei\' !important;background-color:#FFFFFF;\"><span style=\"font-weight:bolder;\">Thu thập thông tin cá nhân</span></span><br />\r\n<span style=\"font-family:\'Microsoft YaHei\', SimSun, Arial;color:#666666;line-height:24px;background-color:#FFFFFF;\">Khi bạn đăng ký hoặc sử dụng các dịch vụ của trang web này, với sự đồng ý của bạn, chúng tôi sẽ thu thập thông tin liên quan đến danh tính cá nhân. Nếu bạn không thể cung cấp thông tin tương ứng, bạn có thể không sử dụng được các dịch vụ tương ứng. Chúng tôi cũng sẽ thu thập các thông tin liên quan khác nhằm mục đích tối ưu hóa trải nghiệm người dùng, để có thể cải thiện các dịch vụ trang web của chúng tôi.</span><br />\r\n<span style=\"font-weight:bolder;font-family:\'Microsoft YaHei\';color:#666666;line-height:24px;background-color:#FFFFFF;\">Sử dụng thông tin cá nhân</span>',1495072059);
